classic:
:root {{ --blue:#2563eb; --navy:#1e3a5f; --bg:#f8fafc; --card:#fff;
         --border:#e2e8f0; --text:#1e293b; --muted:#64748b; }}
* {{ box-sizing:border-box; margin:0; padding:0; }}
body {{ font-family:-apple-system,"Segoe UI",sans-serif; background:var(--bg); color:var(--text); line-height:1.7; }}
header {{ background:var(--navy); color:#fff; padding:0 24px;
          display:flex; align-items:center; justify-content:space-between;
          height:58px; position:sticky; top:0; z-index:100; box-shadow:0 2px 8px rgba(0,0,0,.25); }}
header .logo {{ font-size:1.15rem; font-weight:700; letter-spacing:-.3px; }}
header .logo span {{ color:#60a5fa; }}
header nav a {{ color:rgba(255,255,255,.8); text-decoration:none; margin-left:20px;
                font-size:.9rem; transition:color .15s; }}
header nav a:hover, header nav a.active {{ color:#fff; font-weight:600; }}
.container {{ max-width:860px; margin:0 auto; padding:36px 20px 80px; }}
.card {{ background:var(--card); border:1px solid var(--border); border-radius:12px;
         padding:32px 36px; margin-bottom:24px; box-shadow:0 1px 4px rgba(0,0,0,.06); }}
h1 {{ font-size:1.6rem; color:var(--navy); margin-bottom:6px; }}
h2 {{ font-size:1.2rem; color:var(--blue); margin:2em 0 .6em;
      padding-bottom:6px; border-bottom:2px solid var(--border); }}
h3 {{ font-size:1rem; color:var(--navy); margin:1.4em 0 .4em; }}
p {{ margin-bottom:.9em; }}
a {{ color:var(--blue); }}
ul, ol {{ padding-left:1.4em; margin-bottom:.9em; }}
li {{ margin-bottom:.3em; }}
hr {{ border:none; border-top:1px solid var(--border); margin:2em 0; }}
code {{ background:#f1f5f9; padding:2px 6px; border-radius:4px; font-size:.88em; }}
blockquote {{ border-left:4px solid var(--blue); padding:8px 16px; background:#eff6ff;
              border-radius:0 8px 8px 0; margin:1em 0; color:var(--muted); }}
.meta {{ display:flex; flex-wrap:wrap; gap:8px; margin-bottom:24px; }}
.badge {{ background:#eff6ff; color:var(--blue); border:1px solid #bfdbfe;
          padding:3px 10px; border-radius:20px; font-size:.78rem; font-weight:500; }}
.archive-list {{ list-style:none; padding:0; }}
.archive-list li {{ border-bottom:1px solid var(--border); padding:14px 0; }}
.archive-list li:last-child {{ border-bottom:none; }}
.archive-list a {{ font-weight:500; font-size:1rem; text-decoration:none; }}
.archive-list a:hover {{ text-decoration:underline; }}
.archive-list .date {{ color:var(--muted); font-size:.85rem; margin-top:2px; }}
footer {{ text-align:center; color:var(--muted); font-size:.8rem; padding:24px; border-top:1px solid var(--border); }}
@media (max-width:600px) {{ .card {{ padding:20px; }} header .logo {{ font-size:1rem; }} }}

minimal:
:root {
  --bg:#fafaf7; --surface:#fff; --ink:#16181a; --ink-soft:#3d4248;
  --ink-mute:#8a8f95; --rule:#e6e2da; --accent:#ff5a1f; --chip:#f1efe8;
}
*,*::before,*::after { box-sizing:border-box; }
body { margin:0; background:var(--bg); color:var(--ink); line-height:1.6;
  font-family:'Pretendard Variable','Pretendard',-apple-system,BlinkMacSystemFont,system-ui,sans-serif;
  font-feature-settings:'ss01','ss02'; }

.topbar { max-width:720px; margin:0 auto; padding:28px 24px 24px;
  display:flex; justify-content:space-between; align-items:center;
  border-bottom:1px solid var(--rule); }
.brand { display:flex; align-items:center; gap:10px; font-weight:700;
  letter-spacing:-.02em; font-size:15px; }
.brand-dot { width:22px; height:22px; border-radius:7px; background:var(--ink);
  display:grid; place-items:center; color:var(--bg); font-size:11px; font-weight:800; }
.nav { display:flex; gap:22px; }
.nav a { color:var(--ink-soft); text-decoration:none; font-size:13px; font-weight:500; }
.nav a.on { color:var(--ink); font-weight:700; }

.wrap { max-width:720px; margin:0 auto; padding:56px 24px 80px; }

.eyebrow { font-size:12px; letter-spacing:.18em; text-transform:uppercase;
  color:var(--accent); font-weight:700; margin-bottom:18px;
  display:flex; align-items:center; gap:10px; }
.eyebrow::before { content:''; width:24px; height:1px; background:var(--accent); }

.hero h1 { font-size:46px; line-height:1.1; letter-spacing:-.03em;
  font-weight:800; margin:0 0 22px; text-wrap:balance; }
.hero-meta { display:flex; gap:14px; align-items:center; color:var(--ink-mute);
  font-size:13px; padding-top:18px; border-top:1px solid var(--rule); margin-bottom:48px; }
.hero-meta strong { color:var(--ink); font-weight:600; }
.hero-meta .dot { width:3px; height:3px; background:var(--ink-mute); border-radius:50%; }

.stats { display:grid; grid-template-columns:repeat(4,1fr); gap:0;
  margin-bottom:48px; border-top:1px solid var(--rule); border-bottom:1px solid var(--rule);
  padding:22px 0; }
.stat { padding:0 4px; border-left:1px solid var(--rule); padding-left:18px; }
.stat:first-child { border-left:none; padding-left:0; }
.stat .n { font-size:30px; font-weight:800; letter-spacing:-.04em;
  line-height:1; margin-bottom:6px; font-feature-settings:'tnum'; }
.stat .l { font-size:12px; color:var(--ink-mute); letter-spacing:.04em; }

/* MD 본문 */
.prose { font-size:16px; line-height:1.75; color:var(--ink-soft); }
.prose h1 { font-size:32px; letter-spacing:-.025em; color:var(--ink);
  font-weight:800; margin:0 0 18px; line-height:1.15; }
.prose h2 { font-size:24px; letter-spacing:-.02em; color:var(--ink);
  font-weight:800; margin:48px 0 16px; padding-bottom:10px;
  border-bottom:1px solid var(--rule); }
.prose h3 { font-size:17px; letter-spacing:-.01em; color:var(--ink);
  font-weight:700; margin:32px 0 10px; }
.prose p { margin:0 0 14px; }
.prose a { color:var(--ink); text-decoration:underline; text-decoration-color:var(--rule);
  text-underline-offset:3px; transition:text-decoration-color .15s; }
.prose a:hover { text-decoration-color:var(--accent); }
.prose strong { color:var(--ink); font-weight:700; }
.prose ul, .prose ol { padding-left:0; list-style:none; margin:0 0 18px; }
.prose ul li, .prose ol li { position:relative; padding-left:22px; margin-bottom:10px; }
.prose ul li::before { content:''; position:absolute; left:0; top:11px;
  width:6px; height:6px; border-radius:50%; background:var(--accent); }
.prose ol { counter-reset:o; }
.prose ol li { counter-increment:o; }
.prose ol li::before { content:counter(o,decimal-leading-zero); position:absolute;
  left:0; top:1px; font-size:12px; color:var(--ink-mute); font-weight:700;
  font-feature-settings:'tnum'; }
.prose blockquote { border:none; background:var(--chip); border-radius:10px;
  padding:14px 20px; color:var(--ink-soft); margin:18px 0;
  font-size:14px; }
.prose blockquote p { margin:0; }
.prose hr { border:none; border-top:1px solid var(--rule); margin:40px 0; }
.prose code { background:var(--chip); padding:2px 6px; border-radius:4px;
  font-size:.88em; font-family:'JetBrains Mono',ui-monospace,monospace; }

.sub { background:var(--surface); border:1px solid var(--rule); border-radius:14px;
  padding:32px; text-align:center; margin:56px 0 32px; }
.sub h3 { font-size:20px; letter-spacing:-.02em; font-weight:800; margin:0 0 6px; color:var(--ink); }
.sub p { font-size:14px; color:var(--ink-mute); margin:0 0 18px; }
.sub form { display:flex; gap:8px; max-width:400px; margin:0 auto; }
.sub input { flex:1; padding:11px 14px; border:1px solid var(--rule);
  border-radius:8px; font-size:14px; background:var(--bg); font-family:inherit;
  color:var(--ink); outline:none; }
.sub button { background:var(--ink); color:var(--bg); border:none;
  padding:11px 18px; border-radius:8px; font-size:14px; font-weight:600;
  cursor:pointer; font-family:inherit; }

.archive-list { list-style:none; padding:0; margin:0; }
.archive-list li { display:grid; grid-template-columns:1fr auto auto;
  gap:18px; align-items:center; padding:16px 0; border-bottom:1px solid var(--rule); }
.archive-list a { color:var(--ink); text-decoration:none; font-weight:600;
  font-size:15px; letter-spacing:-.01em; }
.archive-list a:hover { color:var(--accent); }
.archive-list .date { color:var(--ink-mute); font-size:12px;
  font-feature-settings:'tnum'; letter-spacing:.04em; }
.archive-list .arrow { color:var(--ink-mute); font-size:16px; }

.foot { max-width:720px; margin:0 auto; padding:22px 24px 40px;
  border-top:1px solid var(--rule); color:var(--ink-mute); font-size:12px;
  display:flex; justify-content:space-between; }

@media (max-width:640px) {
  .hero h1 { font-size:34px; }
  .stats { grid-template-columns:repeat(2,1fr); gap:18px 0; }
  .stat:nth-child(3) { border-left:none; padding-left:0; }
}

editorial:
:root {
  --ink:#1a1612; --ink-soft:#4a4036; --ink-mute:#8a7e6f;
  --paper:#f4ede0; --paper-2:#ece2cf;
  --rule:#2b231a; --rule-soft:#c8bda7; --accent:#8b2a1f;
}
*,*::before,*::after { box-sizing:border-box; }
body { margin:0; background:var(--paper); color:var(--ink); line-height:1.65;
  font-family:'Noto Serif KR','Source Serif Pro',Georgia,serif; }

.wrap { max-width:980px; margin:0 auto; padding:32px 32px 56px; }

/* Masthead */
.masthead { border-top:6px solid var(--rule); border-bottom:1px solid var(--rule);
  padding:14px 0 12px; margin-bottom:22px; }
.mh-top { display:flex; justify-content:space-between; align-items:baseline;
  font-family:'IBM Plex Mono',monospace; font-size:11px; letter-spacing:.12em;
  color:var(--ink-soft); text-transform:uppercase;
  border-bottom:1px solid var(--rule-soft); padding-bottom:8px; margin-bottom:14px; }
.mh-title { font-weight:900; font-size:84px; letter-spacing:-.04em;
  line-height:.92; text-align:center; margin:6px 0 2px; font-style:italic; }
.mh-title em { color:var(--accent); font-style:italic; }
.mh-tag { font-family:'IBM Plex Mono',monospace; font-size:11px; letter-spacing:.3em;
  text-align:center; color:var(--ink-soft); text-transform:uppercase;
  padding-top:6px; border-top:1px solid var(--rule-soft); margin-top:10px; }
.mh-nav { display:flex; justify-content:center; gap:32px; margin-top:14px;
  font-family:'IBM Plex Mono',monospace; font-size:12px; letter-spacing:.08em;
  text-transform:uppercase; }
.mh-nav a { color:var(--ink-soft); text-decoration:none; }
.mh-nav a.on { color:var(--accent); font-weight:700; border-bottom:2px solid var(--accent); padding-bottom:2px; }

/* Briefing */
.brief { display:grid; grid-template-columns:200px 1fr 160px; gap:24px;
  border-bottom:1px solid var(--rule); padding:18px 0 22px; margin-bottom:28px; }
.brief-stats { font-family:'IBM Plex Mono',monospace; font-size:12px; color:var(--ink-soft); }
.brief-stats .lbl { color:var(--ink); font-weight:700; display:block;
  margin-bottom:8px; letter-spacing:.08em; }
.brief-stat { display:flex; gap:14px; align-items:baseline; margin-top:10px; }
.brief-stat .num { font-family:'Noto Serif KR',serif; font-size:24px;
  font-weight:700; font-style:italic; }
.brief-stat .lab { font-size:10px; letter-spacing:.15em; color:var(--ink-mute); text-transform:uppercase; }
.kicker { font-family:'IBM Plex Mono',monospace; font-size:11px; letter-spacing:.2em;
  text-transform:uppercase; color:var(--accent); margin-bottom:8px;
  border-left:3px solid var(--accent); padding-left:12px; }
.lede { font-size:22px; line-height:1.4; font-weight:500; text-wrap:balance; }
.byline { font-family:'IBM Plex Mono',monospace; font-size:11px; color:var(--ink-mute);
  text-align:right; line-height:1.7; border-left:1px solid var(--rule-soft); padding-left:14px; }

/* MD body */
.prose { font-size:16px; line-height:1.8; }
.prose h1 { font-size:32px; font-weight:900; letter-spacing:-.02em;
  margin:0 0 14px; text-align:center; }
.prose h2 { font-family:'Noto Serif KR',serif; font-size:22px;
  font-weight:800; letter-spacing:-.015em; margin:36px 0 14px;
  padding-bottom:6px; border-bottom:2px solid var(--rule); }
.prose h3 { font-size:17px; font-weight:700; margin:24px 0 8px; }
.prose p { margin:0 0 14px; }
.prose p:first-of-type::first-letter { font-size:54px; font-weight:800;
  float:left; line-height:.9; padding:4px 8px 0 0; color:var(--accent); }
.prose a { color:var(--accent); text-decoration:none;
  border-bottom:1px solid var(--rule-soft); }
.prose a:hover { border-bottom-color:var(--accent); }
.prose strong { color:var(--ink); font-weight:700; }
.prose ul { padding-left:0; list-style:none; columns:2; column-gap:32px;
  column-rule:1px solid var(--rule-soft); margin:0 0 18px; }
.prose ul li { break-inside:avoid; padding:8px 0 8px 20px; position:relative;
  border-bottom:1px dotted var(--rule-soft); font-size:14px; line-height:1.55; }
.prose ul li::before { content:'§'; position:absolute; left:0; top:8px;
  color:var(--accent); font-weight:700; font-family:serif; }
.prose ol { padding-left:1.4em; margin:0 0 18px; }
.prose ol li { margin-bottom:6px; }
.prose blockquote { font-family:'IBM Plex Mono',monospace; font-size:12px;
  border-left:3px solid var(--accent); padding:8px 16px; margin:14px 0;
  background:rgba(139,42,31,.04); color:var(--ink-soft); }
.prose blockquote p { margin:0; }
.prose hr { border:none; border-top:3px double var(--rule); margin:32px 0; }
.prose code { font-family:'IBM Plex Mono',monospace; background:var(--paper-2);
  padding:2px 6px; border-radius:3px; font-size:.85em; }

/* Archive list */
.arch h1 { font-size:32px; font-weight:900; margin:18px 0 6px; }
.arch p.count { font-family:'IBM Plex Mono',monospace; font-size:12px;
  color:var(--ink-mute); letter-spacing:.1em; text-transform:uppercase; margin:0 0 24px; }
.arch ul { list-style:none; padding:0; margin:0;
  columns:2; column-gap:32px; column-rule:1px solid var(--rule-soft); }
.arch li { break-inside:avoid; padding:14px 0; border-bottom:1px solid var(--rule-soft); }
.arch a { color:var(--ink); text-decoration:none; font-weight:600; font-size:16px; }
.arch a:hover { color:var(--accent); }
.arch .d { font-family:'IBM Plex Mono',monospace; font-size:11px;
  color:var(--ink-mute); margin-top:3px; letter-spacing:.04em; }

.foot { border-top:6px solid var(--rule); margin-top:32px; padding-top:14px;
  display:flex; justify-content:space-between; align-items:baseline;
  font-family:'IBM Plex Mono',monospace; font-size:10px; color:var(--ink-mute);
  letter-spacing:.12em; text-transform:uppercase; }

@media (max-width:720px) {
  .mh-title { font-size:54px; }
  .brief { grid-template-columns:1fr; gap:18px; }
  .brief-stats, .byline { border-left:none; padding-left:0; }
  .prose ul, .arch ul { columns:1; }
}

terminal:
:root {
  --bg:#0a0d12; --panel:#11161e; --panel-2:#161c25;
  --line:#1f2733; --line-soft:#182030;
  --ink:#e8eef5; --ink-soft:#a8b3c2; --ink-mute:#5a6675;
  --amber:#f5a524; --green:#2cb67d; --red:#e5484d;
}
*,*::before,*::after { box-sizing:border-box; }
body { margin:0; background:var(--bg); color:var(--ink);
  font-family:'JetBrains Mono','IBM Plex Mono',ui-monospace,monospace;
  font-size:13px; line-height:1.55; }

.topbar { display:flex; align-items:center; background:var(--panel-2);
  border-bottom:1px solid var(--line); padding:8px 16px; font-size:11px;
  letter-spacing:.04em; color:var(--ink-soft); height:34px; }
.topbar .lhs, .topbar .rhs { display:flex; align-items:center; gap:14px; }
.topbar .rhs { margin-left:auto; }
.logo { display:flex; align-items:center; gap:8px; color:var(--amber);
  font-weight:700; letter-spacing:.12em; }
.logo-box { width:16px; height:16px; border:1px solid var(--amber);
  color:var(--amber); display:grid; place-items:center; font-size:9px; font-weight:700; }
.tab { padding:0 10px; color:var(--ink-mute); height:34px;
  display:flex; align-items:center; text-decoration:none;
  margin-top:-8px; margin-bottom:-8px; border-bottom:2px solid transparent; }
.tab.on { color:var(--amber); border-bottom-color:var(--amber);
  background:linear-gradient(180deg,transparent 60%,rgba(245,165,36,.06)); }
.live { display:inline-flex; gap:6px; align-items:center; color:var(--green); font-weight:600; }
.live::before { content:''; width:6px; height:6px; background:var(--green); border-radius:50%;
  box-shadow:0 0 0 3px rgba(44,182,125,.18); animation:pulse 2s ease-in-out infinite; }
@keyframes pulse { 50% { opacity:.4 } }

.wrap { padding:18px 22px; max-width:1200px; margin:0 auto; }

.main-head { display:flex; justify-content:space-between; align-items:flex-end;
  border-bottom:1px solid var(--line); padding-bottom:14px; margin-bottom:18px; }
.main-head h1 { font-size:20px; font-weight:700; letter-spacing:-.01em;
  margin:0; color:var(--ink); }
.main-head h1 .gt { color:var(--amber); }
.main-head .meta { font-size:11px; color:var(--ink-mute);
  text-align:right; line-height:1.7; }
.main-head .ok { color:var(--green); }

.statgrid { display:grid; grid-template-columns:repeat(4,1fr); gap:1px;
  background:var(--line); border:1px solid var(--line);
  margin-bottom:18px; }
.statgrid > div { background:var(--panel); padding:12px 14px; }
.statgrid .l { font-size:10px; color:var(--ink-mute);
  letter-spacing:.12em; text-transform:uppercase; margin-bottom:4px; }
.statgrid .n { font-size:22px; color:var(--ink); font-weight:700;
  font-feature-settings:'tnum'; letter-spacing:-.02em; }
.statgrid .n.amber { color:var(--amber); }
.statgrid .n.green { color:var(--green); }

/* MD body styled like terminal output */
.prose { background:var(--panel); border:1px solid var(--line); padding:18px 22px; }
.prose h1 { font-size:16px; color:var(--amber); font-weight:700;
  margin:0 0 14px; padding-bottom:8px; border-bottom:1px solid var(--line);
  letter-spacing:.06em; }
.prose h1::before { content:'▸ '; color:var(--amber); }
.prose h2 { font-size:13px; color:var(--amber); font-weight:700;
  margin:24px 0 12px; padding:7px 12px;
  background:var(--panel-2); border-left:2px solid var(--amber);
  letter-spacing:.1em; }
.prose h3 { font-size:12px; color:var(--ink); font-weight:600;
  margin:18px 0 8px; letter-spacing:.06em; }
.prose h3::before { content:'## '; color:var(--ink-mute); }
.prose p { color:var(--ink-soft); margin:0 0 10px; font-size:12.5px; line-height:1.65; }
.prose a { color:var(--amber); text-decoration:none; }
.prose a:hover { text-decoration:underline; }
.prose strong { color:var(--ink); }
.prose ul, .prose ol { padding-left:0; list-style:none; margin:0 0 14px; }
.prose li { padding:5px 0 5px 18px; position:relative;
  border-bottom:1px solid var(--line-soft); color:var(--ink-soft);
  font-size:12px; }
.prose li::before { content:'>'; position:absolute; left:0; top:5px;
  color:var(--amber); font-weight:700; }
.prose li:last-child { border-bottom:none; }
.prose blockquote { background:var(--panel-2); border-left:2px solid var(--amber);
  padding:8px 14px; margin:12px 0; color:var(--ink-mute);
  font-size:11px; letter-spacing:.04em; }
.prose blockquote p { margin:0; color:var(--ink-mute); }
.prose hr { border:none; border-top:1px dashed var(--line); margin:20px 0; }
.prose code { background:var(--bg); color:var(--amber); padding:2px 6px;
  border:1px solid var(--line); font-size:.88em; }

/* Archive */
.arch h1 { color:var(--amber); font-size:16px; letter-spacing:.06em; margin:0 0 4px; }
.arch h1::before { content:'▸ '; }
.arch .count { color:var(--ink-mute); font-size:11px;
  letter-spacing:.1em; text-transform:uppercase; margin:0 0 18px; }
.arch table { width:100%; border-collapse:collapse; font-size:12px; }
.arch th { text-align:left; color:var(--ink-mute); font-weight:500;
  letter-spacing:.08em; padding:8px 10px; font-size:10px;
  text-transform:uppercase; border-bottom:1px solid var(--line);
  background:var(--panel-2); }
.arch td { padding:8px 10px; border-bottom:1px solid var(--line-soft);
  color:var(--ink); }
.arch tr:nth-child(even) td { background:rgba(255,255,255,.012); }
.arch tr:hover td { background:rgba(245,165,36,.05); }
.arch a { color:var(--ink); text-decoration:none; }
.arch a:hover { color:var(--amber); }
.arch .date { color:var(--ink-mute); font-feature-settings:'tnum'; width:120px; }

.status { border-top:1px solid var(--line); background:var(--panel-2);
  padding:6px 16px; font-size:10px; color:var(--ink-mute);
  display:flex; gap:16px; height:28px; align-items:center; letter-spacing:.06em; }
.status .ok { color:var(--green); }
.status .spacer { margin-left:auto; }
